def get_dtype_string(dtype) -> str:
    """Convert numpy/h5py dtype to readable string."""
    if hasattr(dtype, 'name'):
        return dtype.name
    elif hasattr(dtype, 'dtype'):
        return dtype.dtype.name
    else:
        return str(dtype)


def get_shape_string(shape) -> str:
    """Convert shape tuple to readable string."""
    if shape is None:
        return "scalar"
    elif isinstance(shape, (tuple, list)):
        return f"({', '.join(map(str, shape))})"
    else:
        return str(shape)


def scan_hdf5_file(filepath: Path) -> Dict[str, Any]:
    """
    Scan an HDF5 file and extract all dataset paths, shapes, and dtypes.

    Args:
        filepath: Path to the HDF5 file

    Returns:
        Dictionary with file metadata and dataset information
    """
    result = {
        'file_type': 'hdf5',
        'file_size_bytes': filepath.stat().st_size,
        'datasets': {},
        'groups': [],
        'attributes': {},
        'error': None
    }

    try:
        with h5py.File(filepath, 'r') as f:
            # Get root attributes
            for attr_name in f.attrs.keys():
                try:
                    attr_value = f.attrs[attr_name]
                    # Convert numpy types to Python types for JSON serialization
                    if isinstance(attr_value, np.ndarray):
                        if attr_value.size == 1:
                            attr_value = attr_value.item()
                        else:
                            attr_value = attr_value.tolist()
                    elif isinstance(attr_value, (np.integer, np.floating)):
                        attr_value = attr_value.item()
                    elif isinstance(attr_value, bytes):
                        attr_value = attr_value.decode('utf-8', errors='replace')
                    result['attributes'][attr_name] = attr_value
                except Exception as e:
                    result['attributes'][attr_name] = f"<error reading attribute: {e}>"

            def visit_item(name, obj):
                """Visitor function for h5py.visititems()"""
                try:
                    if isinstance(obj, h5py.Dataset):
                        result['datasets'][name] = {
                            'shape': get_shape_string(obj.shape),
                            'dtype': get_dtype_string(obj.dtype),
                            'size_bytes': obj.nbytes if hasattr(obj, 'nbytes') else 'unknown',
                            'chunks': get_shape_string(obj.chunks) if obj.chunks else None,
                            'compression': obj.compression if hasattr(obj, 'compression') else None
                        }

                        # Add dataset attributes if any
                        if obj.attrs:
                            attrs = {}
                            for attr_name in obj.attrs.keys():
                                try:
                                    attr_value = obj.attrs[attr_name]
                                    if isinstance(attr_value, np.ndarray):
                                        if attr_value.size == 1:
                                            attr_value = attr_value.item()
                                        else:
                                            attr_value = attr_value.tolist()
                                    elif isinstance(attr_value, (np.integer, np.floating)):
                                        attr_value = attr_value.item()
                                    elif isinstance(attr_value, bytes):
                                        attr_value = attr_value.decode('utf-8', errors='replace')
                                    attrs[attr_name] = attr_value
                                except Exception as e:
                                    attrs[attr_name] = f"<error: {e}>"
                            result['datasets'][name]['attributes'] = attrs

                    elif isinstance(obj, h5py.Group):
                        result['groups'].append(name)

                except Exception as e:
                    # Record problematic items but continue scanning
                    if name not in result['datasets']:
                        result['datasets'][name] = {'error': str(e)}

            # Visit all items in the file
            f.visititems(visit_item)

    except Exception as e:
        result['error'] = str(e)

    return result


def scan_matlab_file(filepath: Path) -> Dict[str, Any]:
    """
    Scan a MATLAB file and extract variable names, shapes, and dtypes.
    Handles both regular .mat files and MATLAB v7.3 format (HDF5-based).

    Args:
        filepath: Path to the MATLAB file

    Returns:
        Dictionary with file metadata and variable information
    """
    result = {
        'file_type': 'matlab',
        'file_size_bytes': filepath.stat().st_size,
        'variables': {},
        'matlab_version': 'unknown',
        'error': None
    }

    # First, try to determine if it's MATLAB v7.3 (HDF5-based)
    is_v73 = False
    try:
        with open(filepath, 'rb') as f:
            header = f.read(8)
            if header.startswith(b'\x89HDF'):
                is_v73 = True
                result['matlab_version'] = 'v7.3 (HDF5-based)'
    except Exception:
        pass

    if is_v73:
        # Handle MATLAB v7.3 files using h5py
        try:
            with h5py.File(filepath, 'r') as f:
                def visit_matlab_var(name, obj):
                    """Visit MATLAB variables stored in HDF5 format"""
                    try:
                        if isinstance(obj, h5py.Dataset):
                            # Skip MATLAB metadata datasets
                            if name.startswith('#') or 'type' in name.lower():
                                return

                            result['variables'][name] = {
                                'shape': get_shape_string(obj.shape),
                                'dtype': get_dtype_string(obj.dtype),
                                'size_bytes': obj.nbytes if hasattr(obj, 'nbytes') else 'unknown'
                            }

                            # Add MATLAB-specific attributes
                            if obj.attrs:
                                attrs = {}
                                for attr_name in obj.attrs.keys():
                                    try:
                                        attr_value = obj.attrs[attr_name]
                                        if isinstance(attr_value, bytes):
                                            attr_value = attr_value.decode('utf-8', errors='replace')
                                        elif isinstance(attr_value, np.ndarray):
                                            if attr_value.size == 1:
                                                attr_value = attr_value.item()
                                            else:
                                                attr_value = attr_value.tolist()
                                        attrs[attr_name] = attr_value
                                    except Exception:
                                        attrs[attr_name] = "<error reading attribute>"
                                if attrs:
                                    result['variables'][name]['attributes'] = attrs

                    except Exception as e:
                        result['variables'][name] = {'error': str(e)}

                f.visititems(visit_matlab_var)

        except Exception as e:
            result['error'] = f"Failed to read MATLAB v7.3 file: {e}"
    else:
        # Handle regular MATLAB files using scipy.io.loadmat
        try:
            # Use scipy.io.loadmat with struct_as_record=False for better handling
            mat_data = scipy.io.loadmat(
                str(filepath), 
                squeeze_me=False, 
                struct_as_record=False,
                mat_dtype=True
            )
            result['matlab_version'] = 'v7.0 or earlier'

            for var_name, var_data in mat_data.items():
                # Skip MATLAB metadata variables
                if var_name.startswith('__'):
                    continue

                try:
                    if isinstance(var_data, np.ndarray):
                        result['variables'][var_name] = {
                            'shape': get_shape_string(var_data.shape),
                            'dtype': get_dtype_string(var_data.dtype),
                            'size_bytes': var_data.nbytes
                        }

                        # Handle MATLAB structs
                        if var_data.dtype.names:
                            result['variables'][var_name]['struct_fields'] = list(var_data.dtype.names)
                            result['variables'][var_name]['is_struct'] = True
                        else:
                            result['variables'][var_name]['is_struct'] = False

                    else:
                        result['variables'][var_name] = {
                            'shape': 'scalar',
                            'dtype': type(var_data).__name__,
                            'size_bytes': sys.getsizeof(var_data)
                        }

                except Exception as e:
                    result['variables'][var_name] = {'error': str(e)}

        except Exception as e:
            result['error'] = f"Failed to read MATLAB file: {e}"

    return result


def find_common_patterns(file_paths: List[Path]) -> Dict[str, List[Path]]:
    """
    Group file paths by common patterns, creating wildcards for repeated structures.

    Args:
        file_paths: List of file paths

    Returns:
        Dictionary mapping patterns to lists of matching files
    """
    patterns = defaultdict(list)

    for path in file_paths:
        path_str = str(path)

        # Look for subject_N patterns
        if 'subject_' in path_str:
            # Replace subject_N with subject_*
            pattern = path_str
            import re
            pattern = re.sub(r'subject_\d+', 'subject_*', pattern)
            patterns[pattern].append(path)
        else:
            # No pattern, use the path as-is
            patterns[path_str].append(path)

    return dict(patterns)


