#!/usr/bin/env python3
"""
Scan neuroscience data directory for HDF5 and MATLAB files and generate metadata.

This script recursively scans a directory containing neuroscience data files,
extracts metadata from HDF5 and MATLAB files, and outputs a summary in JSON format.
"""

import argparse
import json
import os
import re
import sys
from collections import defaultdict
from pathlib import Path
from typing import Dict, List, Tuple, Any, Optional

import h5py
import numpy as np
import scipy.io


def parse_args():
    """Parse command line arguments."""
    parser = argparse.ArgumentParser(
        description="Scan neuroscience data directory and generate metadata JSON"
    )
    parser.add_argument(
        "root_dir",
        type=str,
        help="Root directory containing the neuroscience data files"
    )
    parser.add_argument(
        "-o", "--output",
        type=str,
        default="meta.json",
        help="Output JSON file path (default: meta.json)"
    )
    parser.add_argument(
        "-v", "--verbose",
        action="store_true",
        help="Enable verbose output"
    )
    return parser.parse_args()


def get_dtype_string(dtype) -> str:
    """Convert numpy dtype to string representation."""
    if isinstance(dtype, np.dtype):
        return str(dtype)
    return str(dtype)


def scan_hdf5_group(group: h5py.Group, prefix: str = "") -> List[Dict[str, Any]]:
    """Recursively scan HDF5 group for datasets."""
    datasets = []

    for key in group.keys():
        item = group[key]
        path = f"{prefix}/{key}" if prefix else f"/{key}"

        if isinstance(item, h5py.Dataset):
            datasets.append({
                "path": path,
                "shape": list(item.shape),
                "dtype": get_dtype_string(item.dtype)
            })
        elif isinstance(item, h5py.Group):
            # Recursively scan subgroups
            datasets.extend(scan_hdf5_group(item, path))

    return datasets


def read_hdf5_file(filepath: Path) -> Tuple[Optional[List[Dict[str, Any]]], Optional[str]]:
    """Read HDF5 file and extract dataset information."""
    try:
        with h5py.File(filepath, 'r') as f:
            datasets = scan_hdf5_group(f)
            return datasets, None
    except Exception as e:
        return None, f"Error reading HDF5 file: {str(e)}"


def read_mat_file_v73(filepath: Path) -> Tuple[Optional[Dict[str, Dict[str, Any]]], Optional[str]]:
    """Read MATLAB v7.3 file using h5py."""
    try:
        variables = {}
        with h5py.File(filepath, 'r') as f:
            for key in f.keys():
                if key.startswith('#'):  # Skip MATLAB metadata
                    continue

                item = f[key]
                if isinstance(item, h5py.Dataset):
                    variables[key] = {
                        "shape": list(item.shape),
                        "dtype": get_dtype_string(item.dtype)
                    }
                elif isinstance(item, h5py.Group):
                    # For complex MATLAB structures, just note it as a struct
                    variables[key] = {
                        "shape": "struct",
                        "dtype": "matlab_struct"
                    }
        return variables, None
    except Exception as e:
        return None, f"Error reading MATLAB v7.3 file: {str(e)}"


def read_mat_file(filepath: Path) -> Tuple[Optional[Dict[str, Dict[str, Any]]], Optional[str]]:
    """Read MATLAB file and extract variable information."""
    try:
        # First try with scipy.io.loadmat
        mat_data = scipy.io.loadmat(filepath, squeeze_me=False, mat_dtype=True)
        variables = {}

        for key, value in mat_data.items():
            if key.startswith('__'):  # Skip metadata keys
                continue

            if isinstance(value, np.ndarray):
                variables[key] = {
                    "shape": list(value.shape),
                    "dtype": get_dtype_string(value.dtype)
                }
            else:
                variables[key] = {
                    "shape": "unknown",
                    "dtype": str(type(value).__name__)
                }

        return variables, None

    except NotImplementedError:
        # This is likely a v7.3 file, try with h5py
        return read_mat_file_v73(filepath)
    except Exception as e:
        # Try h5py as fallback for v7.3 files
        result, error = read_mat_file_v73(filepath)
        if result is not None:
            return result, None
        return None, f"Error reading MATLAB file: {str(e)}"


def find_pattern(paths: List[str]) -> Optional[str]:
    """Find common pattern in paths with wildcards for varying parts."""
    if len(paths) <= 1:
        return None

    # Check if all paths have the same structure
    parts_list = [Path(p).parts for p in paths]
    if not all(len(parts) == len(parts_list[0]) for parts in parts_list):
        return None

    # Find differing parts and create pattern
    pattern_parts = []
    for i in range(len(parts_list[0])):
        unique_parts = set(parts[i] for parts in parts_list)
        if len(unique_parts) == 1:
            pattern_parts.append(parts_list[0][i])
        else:
            # Check if parts match a pattern like subject_0, subject_1, etc.
            if all(re.match(r'^subject_\d+$', part) for part in unique_parts):
                pattern_parts.append('subject_*')
            else:
                return None  # Can't create a simple pattern

    return str(Path(*pattern_parts))


def scan_directory(root_dir: Path, verbose: bool = False) -> Dict[str, Any]:
    """Scan directory for HDF5 and MATLAB files."""
    file_info = {}
    errors = []

    # Find all .h5 and .mat files
