    mat_files = list(root_dir.rglob("*.mat"))

    if verbose:
        print(f"Found {len(h5_files)} HDF5 files and {len(mat_files)} MATLAB files")

    # Process HDF5 files
    for filepath in h5_files:
        rel_path = str(filepath.relative_to(root_dir))
        if verbose:
            print(f"Processing HDF5: {rel_path}")

        datasets, error = read_hdf5_file(filepath)
        if error:
            errors.append({"file": rel_path, "error": error})
            continue

        file_info[rel_path] = {
            "type": "HDF5",
            "datasets": datasets
        }

    # Process MATLAB files
    for filepath in mat_files:
        rel_path = str(filepath.relative_to(root_dir))
        if verbose:
            print(f"Processing MATLAB: {rel_path}")

        variables, error = read_mat_file(filepath)
        if error:
            errors.append({"file": rel_path, "error": error})
            continue

        file_info[rel_path] = {
            "type": "MATLAB",
            "variables": variables
        }

    return file_info, errors


