    """Merge similar files into wildcard patterns."""
    # Group files by their pattern
    pattern_groups = defaultdict(list)
    merged_info = {}

    # First, group files that might have patterns
    for filepath, info in file_info.items():
        # Check if this is a subject file
        if re.search(r'subject_\d+', filepath):
            # Replace subject number with placeholder
            pattern = re.sub(r'subject_\d+', 'subject_*', filepath)
            pattern_groups[pattern].append((filepath, info))
        else:
            # Non-pattern files go directly to merged_info
            merged_info[filepath] = info

    # Process pattern groups
    for pattern, file_list in pattern_groups.items():
        if len(file_list) > 1:
            # Verify all files in group have same structure
            first_info = file_list[0][1]
            all_same = True

            if first_info['type'] == 'HDF5':
                # Check if all HDF5 files have same datasets
                first_datasets = {d['path']: (tuple(d['shape']), d['dtype']) 
                                for d in first_info['datasets']}

                for _, info in file_list[1:]:
                    if info['type'] != 'HDF5':
                        all_same = False
                        break

                    datasets = {d['path']: (tuple(d['shape']), d['dtype']) 
                              for d in info['datasets']}
                    if datasets != first_datasets:
                        all_same = False
                        break

            elif first_info['type'] == 'MATLAB':
                # Check if all MATLAB files have same variables
                first_vars = {k: (v['shape'], v['dtype']) 
                            for k, v in first_info['variables'].items()}

                for _, info in file_list[1:]:
                    if info['type'] != 'MATLAB':
                        all_same = False
                        break

                    vars_check = {k: (v['shape'], v['dtype']) 
                                for k, v in info['variables'].items()}
                    if vars_check != first_vars:
                        all_same = False
                        break

            if all_same:
                merged_info[pattern] = {
                    **first_info,
                    "count": len(file_list),
                    "files": [f[0] for f in file_list]
                }
            else:
                # If not all same, add individually
                for filepath, info in file_list:
                    merged_info[filepath] = info
        else:
            # Single file, add directly
            merged_info[file_list[0][0]] = file_list[0][1]

    return merged_info


def generate_summary(file_info: Dict[str, Any]) -> Dict[str, Any]:
    """Generate summary statistics."""
    total_files = 0
    h5_files = 0
    mat_files = 0
    total_datasets = 0
    total_variables = 0

    for filepath, info in file_info.items():
        count = info.get('count', 1)
        total_files += count

        if info['type'] == 'HDF5':
            h5_files += count
            total_datasets += len(info['datasets']) * count
        elif info['type'] == 'MATLAB':
            mat_files += count
            total_variables += len(info['variables']) * count

    return {
        "total_files": total_files,
        "hdf5_files": h5_files,
        "matlab_files": mat_files,
        "total_hdf5_datasets": total_datasets,
        "total_matlab_variables": total_variables
    }


def main():
    """Main function."""
    args = parse_args()

    root_dir = Path(args.root_dir)
    if not root_dir.exists():
        print(f"Error: Directory '{root_dir}' does not exist")
        sys.exit(1)

    if not root_dir.is_dir():
        print(f"Error: '{root_dir}' is not a directory")
        sys.exit(1)

    print(f"Scanning directory: {root_dir}")

    # Scan directory
    file_info, errors = scan_directory(root_dir, args.verbose)

    # Merge similar files
    merged_info = merge_similar_files(file_info)

    # Generate summary
    summary = generate_summary(merged_info)

    # Create output structure
    output = {
        "root_directory": str(root_dir.absolute()),
        "summary": summary,
        "files": merged_info
    }

    if errors:
        output["errors"] = errors

    # Write output
    output_path = Path(args.output)
    try:
        with open(output_path, 'w') as f:
            json.dump(output, f, indent=2)
        print(f"Metadata written to: {output_path}")

        # Print summary
        print(f"\nSummary:")
        print(f"  Total files: {summary['total_files']}")
        print(f"  HDF5 files: {summary['hdf5_files']}")
        print(f"  MATLAB files: {summary['matlab_files']}")
        print(f"  Total HDF5 datasets: {summary['total_hdf5_datasets']}")
        print(f"  Total MATLAB variables: {summary['total_matlab_variables']}")

        if errors:
            print(f"\nEncountered {len(errors)} errors during scanning")

    except Exception as e:
        print(f"Error writing output file: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()
