```python
#!/usr/bin/env python3
"""
Zebrafish Dataset Metadata Scanner

Recursively scans a directory tree for HDF5 and MATLAB files, extracts metadata
(dataset paths, shapes, dtypes), and outputs a structured JSON summary with
wildcard patterns for repeated structures.

Usage:
    python scan_zebrafish_data.py /path/to/dataset_root -o meta.json
"""

import argparse
import json
import os
import re
import sys
import warnings
from collections import defaultdict
from pathlib import Path
from typing import Dict, List, Tuple, Any, Optional

import h5py
import numpy as np
import scipy.io

# Suppress specific warnings
warnings.filterwarnings('ignore', category=FutureWarning)
warnings.filterwarnings('ignore', category=DeprecationWarning)


class DatasetScanner:
    """Scans HDF5 and MATLAB files for metadata."""

    def __init__(self, verbose: bool = False):
        self.verbose = verbose
        self.errors = []

    def scan_directory(self, root_path: Path) -> Dict[str, Any]:
        """Scan directory tree for data files and extract metadata."""
        if self.verbose:
            print(f"Scanning directory: {root_path}")

        # Find all relevant files
        h5_files = list(root_path.rglob("*.h5"))
        hdf5_files = list(root_path.rglob("*.hdf5"))
        mat_files = list(root_path.rglob("*.mat"))

        all_h5_files = h5_files + hdf5_files

        if self.verbose:
            print(f"Found {len(all_h5_files)} HDF5 files and {len(mat_files)} MATLAB files")

        # Process files
        file_metadata = {}

        for filepath in all_h5_files:
            rel_path = filepath.relative_to(root_path)
            try:
                metadata = self.scan_hdf5_file(filepath)
                file_metadata[str(rel_path)] = {
                    "type": "hdf5",
                    "absolute_path": str(filepath),
                    "size_bytes": filepath.stat().st_size,
                    "metadata": metadata
                }
            except Exception as e:
                self.errors.append({
                    "file": str(rel_path),
                    "error": str(e),
                    "type": type(e).__name__
                })
                if self.verbose:
                    print(f"Error scanning {rel_path}: {e}")

        for filepath in mat_files:
            rel_path = filepath.relative_to(root_path)
            try:
                metadata = self.scan_mat_file(filepath)
                file_metadata[str(rel_path)] = {
                    "type": "matlab",
                    "absolute_path": str(filepath),
                    "size_bytes": filepath.stat().st_size,
                    "metadata": metadata
                }
            except Exception as e:
                self.errors.append({
                    "file": str(rel_path),
                    "error": str(e),
                    "type": type(e).__name__
                })
                if self.verbose:
                    print(f"Error scanning {rel_path}: {e}")

        return file_metadata

    def scan_hdf5_file(self, filepath: Path) -> Dict[str, Any]:
        """Extract metadata from HDF5 file."""
        datasets = {}
        groups = []
        attributes = {}

        with h5py.File(filepath, 'r') as f:
            # Get file-level attributes
            for key, value in f.attrs.items():
                attributes[key] = self._serialize_attribute(value)

            # Recursively scan groups and datasets
            def visit_item(name, obj):
                if isinstance(obj, h5py.Dataset):
                    datasets[name] = {
                        "shape": obj.shape,
                        "dtype": str(obj.dtype),
                        "size_bytes": obj.nbytes,
                        "chunks": obj.chunks,
                        "compression": obj.compression,
                        "attributes": {k: self._serialize_attribute(v) 
                                     for k, v in obj.attrs.items()}
                    }
                elif isinstance(obj, h5py.Group):
                    groups.append(name)

            f.visititems(visit_item)

        return {
            "datasets": datasets,
            "groups": groups,
            "attributes": attributes,
            "n_datasets": len(datasets),
            "n_groups": len(groups)
        }

    def scan_mat_file(self, filepath: Path) -> Dict[str, Any]:
        """Extract metadata from MATLAB file, handling both v5 and v7.3 formats."""
        try:
            # Try scipy.io.loadmat first (for v5 and earlier)
            mat_data = scipy.io.loadmat(filepath, squeeze_me=False, 
                                       struct_as_record=True,
                                       mat_dtype=True)
            return self._scan_mat_v5(mat_data)
        except NotImplementedError:
            # Fall back to h5py for v7.3 files
            if self.verbose:
                print(f"  {filepath.name} is MATLAB v7.3, using h5py")
            return self._scan_mat_v73(filepath)
        except Exception as e:
            # Re-raise with more context
            raise RuntimeError(f"Failed to read MATLAB file: {e}") from e

    def _scan_mat_v5(self, mat_data: Dict) -> Dict[str, Any]:
        """Process MATLAB v5 data loaded by scipy."""
        variables = {}

        for key, value in mat_data.items():
            # Skip internal MATLAB variables
            if key.startswith('__'):
                continue

            var_info = {
                "shape": value.shape if hasattr(value, 'shape') else None,
                "dtype": str(value.dtype) if hasattr(value, 'dtype') else type(value).__name__,
                "type": type(value).__name__
            }

            # Add extra info for structured arrays
            if hasattr(value, 'dtype') and value.dtype.names:
                var_info["fields"] = list(value.dtype.names)

            variables[key] = var_info

        return {
            "format": "MATLAB v5",
            "variables": variables,
            "n_variables": len(variables)
        }

    def _scan_mat_v73(self, filepath: Path) -> Dict[str, Any]:
        """Process MATLAB v7.3 files using h5py."""
        variables = {}

        with h5py.File(filepath, 'r') as f:
            for key in f.keys():
                if key.startswith('#'):  # Skip MATLAB internal references
                    continue

                obj = f[key]
                if isinstance(obj, h5py.Dataset):
                    variables[key] = {
                        "shape": obj.shape,
                        "dtype": str(obj.dtype),
                        "type": "dataset"
                    }
                elif isinstance(obj, h5py.Group):
                    # MATLAB structs are stored as groups
                    variables[key] = {
                        "type": "struct",
                        "fields": list(obj.keys())
                    }

        return {
            "format": "MATLAB v7.3 (HDF5)",
            "variables": variables,
            "n_variables": len(variables)
        }

    def _serialize_attribute(self, value: Any) -> Any:
        """Convert HDF5 attributes to JSON-serializable format."""
        if isinstance(value, np.ndarray):
            return value.tolist()
        elif isinstance(value, (np.integer, np.floating)):
            return value.item()
        elif isinstance(value, bytes):
            return value.decode('utf-8', errors='replace')
        else:
            return str(value)


def create_wildcard_patterns(file_metadata: Dict[str, Any]) -> Dict[str, List[str]]:
    """Group similar file paths into wildcard patterns."""
    patterns = defaultdict(list)

    # Regular expression to match subject directories
    subject_pattern = re.compile(r'subject_(\d+)')

    for filepath in file_metadata.keys():
        # Replace subject numbers with wildcards
        wildcard_path = subject_pattern.sub('subject_*', filepath)
        patterns[wildcard_path].append(filepath)

    return dict(patterns)


def generate_summary(file_metadata: Dict[str, Any], 
                    patterns: Dict[str, List[str]]) -> Dict[str, Any]:
    """Generate summary statistics for the dataset."""
    summary = {
        "total_files": len(file_metadata),
        "file_types": defaultdict(int),
        "total_size_bytes": 0,
        "unique_patterns": len(patterns),
        "subjects": set(),
        "common_datasets": defaultdict(int),
        "common_variables": defaultdict(int)
    }

    subject_pattern = re.compile(r'subject_(\d+)')

    for filepath, info in file_metadata.items():
        # Count file types
        summary["file_types"][info["type"]] += 1
        summary["total_size_bytes"] += info["size_bytes"]

        # Extract subject numbers
        match = subject_pattern.search(filepath)
        if match:
            summary["subjects"].add(int(match.group(1)))

        # Count common datasets/variables
        if info["type"] == "hdf5":
            for dataset_path in info["metadata"]["datasets"]:
                summary["common_datasets"][dataset_path] += 1
        elif info["type"] == "matlab":
            for var_name in info["metadata"]["variables"]:
                summary["common_variables"][var_name] += 1

    # Convert sets to sorted lists for JSON serialization
    summary["subjects"] = sorted(list(summary["subjects"]))
    summary["file_types"] = dict(summary["file_types"])
    summary["common_datasets"] = dict(summary["common_datasets"])
    summary["common_variables"] = dict(summary["common_variables"])

    # Add human-readable size
    size_mb = summary["total_size_bytes"] / (1024 * 1024)
    summary["total_size_human"] = f"{size_mb:.2f} MB"

    return summary


def main():
    parser = argparse.ArgumentParser(
        description="Scan zebrafish imaging dataset and generate metadata JSON",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Example:
    python scan_zebrafish_data.py /data/zebrafish_dataset -o meta.json -v
        """
    )

    parser.add_argument(
        "root_directory",
        type=Path,
        help="Root directory of the dataset"
    )

    parser.add_argument(
        "-o", "--output",
        type=Path,
        default=Path("meta.json"),
        help="Output JSON file path (default: meta.json)"
    )

    parser.add_argument(
        "-v", "--verbose",
        action="store_true",
        help="Enable verbose output"
    )

    parser.add_argument(
        "--indent",
        type=int,
        default=2,
        help="JSON indentation level (default: 2)"
    )

    args = parser.parse_args()

    # Validate input directory
    if not args.root_directory.exists():
        print(f"Error: Directory '{args.root_directory}' does not exist", file=sys.stderr)
        sys.exit(1)

    if not args.root_directory.is_dir():
        print(f"Error: '{args.root_directory}' is not a directory", file=sys.stderr)
        sys.exit(1)

    # Check write permissions for output
    output_dir = args.output.parent
    if not output_dir.exists():
        try:
            output_dir.mkdir(parents=True)
        except PermissionError:
            print(f"Error: Cannot create output directory '{output_dir}'", file=sys.stderr)
            sys.exit(1)

    # Scan the dataset
    scanner = DatasetScanner(verbose=args.verbose)

    try:
        file_metadata = scanner.scan_directory(args.root_directory)
    except PermissionError as e:
        print(f"Error: Permission denied while scanning: {e}", file=sys.stderr)
        sys.exit(1)

    # Create wildcard patterns
    patterns = create_wildcard_patterns(file_metadata)

    # Generate summary
    summary = generate_summary(file_metadata, patterns)

    # Prepare output
    output_data = {
        "dataset_root": str(args.root_directory.absolute()),
        "scan_timestamp": np.datetime64('now').item().isoformat(),
        "summary": summary,
        "patterns": patterns,
        "files": file_metadata,
        "errors": scanner.errors
    }

    # Write output
    try:
        with open(args.output, 'w') as f:
            json.dump(output_data, f, indent=args.indent, sort_keys=True)
        print(f"Successfully wrote metadata to '{args.output}'")

        if scanner.errors:
            print(f"\nWarning: {len(scanner.errors)} files had errors during scanning")
            if args.verbose:
                print("\nErrors:")
                for error in scanner.errors:
                    print(f"  - {error['file']}: {error['error']}")

    except (PermissionError, IOError) as e:
        print(f"Error: Cannot write to '{args.output}': {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()
